definition.script:
pipeline {
    agent {
        label "${BUILDNODE}"
    }
    stages {
        stage('Import certificates') {
            steps {
                withCredentials([file(credentialsId: 'MacOSCodesignSAP', variable: 'signcertp2'),
                                string(credentialsId: 'MacOSCodesignSAP-Password', variable: 'signcertpass')]) {
                    sh 'security import $signcertp2 -k ~/Library/Keychains/login.keychain -P $signcertpass'
                }
            }
        }
    }
    post {
        always {
            cleanWs deleteDirs: true, disableDeferredWipeout: true
        }
    }
}
